"use client"

import { RangeChart } from "@/components/ui/charts"

const stockData = [
  { category: "Q1", low: 100, high: 145, mid: 120 },
  { category: "Q2", low: 130, high: 180, mid: 155 },
  { category: "Q3", low: 155, high: 210, mid: 180 },
  { category: "Q4", low: 175, high: 240, mid: 210 },
]

export default function RangeChartHorizontal() {
  return (
    <RangeChart
      data={stockData}
      variant="band"
      showMidLine={true}
      showMarkers={true}
      lowLabel="Low"
      highLabel="High"
      midLabel="Close"
      color="#10b981"
      fillOpacity={0.35}
      valueFormatter={(v) => `$${v}`}
    />
  )
}
